examples.bad:
Task {
  let user = try await api.fetchUser()
  self.nameLabel.text = user.name // ❌ UI update off main thread
}

examples.good:
Task {
  let user = try await api.fetchUser()
  await MainActor.run { self.nameLabel.text = user.name }
}

examples.bad:
DispatchQueue.global(qos: .background).async {
  let result = heavyComputation()
  DispatchQueue.main.async { self.update(result) }
}

examples.good:
Task.detached(priority: .background) {
  let result = await heavyComputation()
  await MainActor.run { self.update(result) }
}

examples.bad:
class Cache {
  var data: [String: Any] = [:] // ❌ Unsafe shared mutable state
}

examples.good:
actor Cache {
  private var data: [String: Any] = [:]
  func set(_ value: Any, for key: String) { data[key] = value }
}

examples.bad:
Task {
  for item in largeList {
    process(item) // Never checks cancellation
  }
}

examples.good:
Task {
  for item in largeList {
    try Task.checkCancellation()
    process(item)
  }
}

Task {
  let (data, _) = try await URLSession.shared.data(from: remoteURL)
  await MainActor.run { self.processData(data) }
}
